async function seed() {
  const sb = createClient(SUPABASE_URL, SERVICE_ROLE_KEY, {
    auth: { autoRefreshToken: false, persistSession: false }
  })

  const { data: profile, error: pErr } = await sb
    .from('profiles').select('id, biz_name').eq('id', DIST_ID).single()

  if (pErr || !profile) {
    console.error('DIST_ID not found. Complete signup first.')
    process.exit(1)
  }
  console.log('Found distributor:', profile.biz_name || profile.id)

  const { count } = await sb
    .from('medicines').select('id', { count: 'exact', head: true }).eq('dist_id', DIST_ID)

  if (count && count > 0) {
    console.log(count + ' medicines already exist. Skipping.')
    process.exit(0)
  }

  const rows = medicines.map(m => ({
    dist_id: DIST_ID, code: m.code || null, name: m.name,
    company: m.company || null, tp: m.tp, disc: m.disc || 0,
    bonus: m.bonus || null, stock: 999
  }))

  const BATCH = 500
  let inserted = 0
  for (let i = 0; i < rows.length; i += BATCH) {
    const { error } = await sb.from('medicines').insert(rows.slice(i, i + BATCH))
    if (error) { console.error('Insert failed:', error.message); process.exit(1) }
    inserted += Math.min(BATCH, rows.length - i)
    console.log('Inserted ' + inserted + '/' + rows.length)
  }
  console.log('Done. ' + inserted + ' medicines inserted.')
}

seed().catch(err => { console.error(err.message); process.exit(1) })
